21	/// The number of shards per sharded lock. Must be a power of two.
22	const NUM_SHARDS: usize = 8;
23	
24	/// A shard containing a single reader-writer lock.
25	struct Shard {
26	    /// The inner reader-writer lock.
27	    lock: RwLock<()>,
28	
29	    /// The write-guard keeping this shard locked.
30	    ///
31	    /// Write operations will lock each shard and store the guard here. These guards get dropped at
32	    /// the same time the big guard is dropped.
33	    write_guard: UnsafeCell<Option<RwLockWriteGuard<'static, ()>>>,
34	}
