310	    /// Attempts to acquire this lock with exclusive write access.
311	    ///
312	    /// If the access could not be granted at this time, an error is returned. Otherwise, a guard
313	    /// is returned which will release the exclusive access when it is dropped. This method does
314	    /// not provide any guarantees with respect to the ordering of whether contentious readers or
315	    /// writers will acquire the lock first.
316	    ///
317	    /// # Errors
318	    ///
319	    /// This method will return an error if the lock is poisoned. A lock gets poisoned when a write
320	    /// operation panics.
321	    ///
322	    /// # Examples
323	    ///
324	    /// ```
325	    /// use crossbeam_utils::sync::ShardedLock;
326	    ///
327	    /// let lock = ShardedLock::new(1);
328	    ///
329	    /// let n = lock.read().unwrap();
330	    /// assert_eq!(*n, 1);
331	    ///
332	    /// assert!(lock.try_write().is_err());
333	    /// ```
334	    pub fn try_write(&self) -> TryLockResult<ShardedLockWriteGuard<'_, T>> {
335	        let mut poisoned = false;
336	        let mut blocked = None;
337	
338	        // Write-lock each shard in succession.
339	        for (i, shard) in self.shards.iter().enumerate() {
340	            let guard = match shard.lock.try_write() {
341	                Ok(guard) => guard,
342	                Err(TryLockError::Poisoned(err)) => {
343	                    poisoned = true;
344	                    err.into_inner()
345	                }
346	                Err(TryLockError::WouldBlock) => {
347	                    blocked = Some(i);
348	                    break;
349	                }
350	            };
351	
352	            // Store the guard into the shard.
353	            unsafe {
354	                let guard: RwLockWriteGuard<'static, ()> = mem::transmute(guard);
355	                let dest: *mut _ = shard.write_guard.get();
356	                *dest = Some(guard);
357	            }
358	        }
359	
360	        if let Some(i) = blocked {
361	            // Unlock the shards in reverse order of locking.
362	            for shard in self.shards[0..i].iter().rev() {
363	                unsafe {
364	                    let dest: *mut _ = shard.write_guard.get();
365	                    let guard = (*dest).take();
366	                    drop(guard);
367	                }
368	            }
369	            Err(TryLockError::WouldBlock)
370	        } else if poisoned {
371	            let guard = ShardedLockWriteGuard {
372	                lock: self,
373	                _marker: PhantomData,
374	            };
375	            Err(TryLockError::Poisoned(PoisonError::new(guard)))
376	        } else {
377	            Ok(ShardedLockWriteGuard {
378	                lock: self,
379	                _marker: PhantomData,
380	            })
381	        }
382	    }
383	
384	    /// Locks with exclusive write access, blocking the current thread until it can be acquired.
385	    ///
386	    /// The calling thread will be blocked until there are no more writers which hold the lock.
387	    /// There may be other readers currently inside the lock when this method returns. This method
388	    /// does not provide any guarantees with respect to the ordering of whether contentious readers
389	    /// or writers will acquire the lock first.
390	    ///
391	    /// Returns a guard which will release the exclusive access when dropped.
392	    ///
393	    /// # Errors
394	    ///
395	    /// This method will return an error if the lock is poisoned. A lock gets poisoned when a write
396	    /// operation panics.
397	    ///
398	    /// # Panics
399	    ///
400	    /// This method might panic when called if the lock is already held by the current thread.
401	    ///
402	    /// # Examples
403	    ///
404	    /// ```
405	    /// use crossbeam_utils::sync::ShardedLock;
406	    ///
407	    /// let lock = ShardedLock::new(1);
408	    ///
409	    /// let mut n = lock.write().unwrap();
410	    /// *n = 2;
411	    ///
412	    /// assert!(lock.try_read().is_err());
413	    /// ```
414	    pub fn write(&self) -> LockResult<ShardedLockWriteGuard<'_, T>> {
415	        let mut poisoned = false;
416	
417	        // Write-lock each shard in succession.
418	        for shard in self.shards.iter() {
419	            let guard = match shard.lock.write() {
420	                Ok(guard) => guard,
421	                Err(err) => {
422	                    poisoned = true;
423	                    err.into_inner()
424	                }
425	            };
426	
427	            // Store the guard into the shard.
428	            unsafe {
429	                let guard: RwLockWriteGuard<'_, ()> = guard;
430	                let guard: RwLockWriteGuard<'static, ()> = mem::transmute(guard);
431	                let dest: *mut _ = shard.write_guard.get();
432	                *dest = Some(guard);
433	            }
434	        }
435	
436	        if poisoned {
437	            Err(PoisonError::new(ShardedLockWriteGuard {
438	                lock: self,
439	                _marker: PhantomData,
440	            }))
441	        } else {
442	            Ok(ShardedLockWriteGuard {
443	                lock: self,
444	                _marker: PhantomData,
445	            })
446	        }
447	    }
448	}
