450	impl<T: ?Sized + fmt::Debug> fmt::Debug for ShardedLock<T> {
451	    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
452	        match self.try_read() {
453	            Ok(guard) => f
454	                .debug_struct("ShardedLock")
455	                .field("data", &&*guard)
456	                .finish(),
457	            Err(TryLockError::Poisoned(err)) => f
458	                .debug_struct("ShardedLock")
459	                .field("data", &&**err.get_ref())
460	                .finish(),
461	            Err(TryLockError::WouldBlock) => {
462	                struct LockedPlaceholder;
463	                impl fmt::Debug for LockedPlaceholder {
464	                    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
465	                        f.write_str("<locked>")
466	                    }
467	                }
468	                f.debug_struct("ShardedLock")
469	                    .field("data", &LockedPlaceholder)
470	                    .finish()
471	            }
472	        }
473	    }
474	}
