530	    fn drop(&mut self) {
531	        // Unlock the shards in reverse order of locking.
532	        for shard in self.lock.shards.iter().rev() {
533	            unsafe {
534	                let dest: *mut _ = shard.write_guard.get();
535	                let guard = (*dest).take();
536	                drop(guard);
537	            }
538	        }
