570	/// Returns a `usize` that identifies the current thread.
571	///
572	/// Each thread is associated with an 'index'. While there are no particular guarantees, indices
573	/// usually tend to be consecutive numbers between 0 and the number of running threads.
574	///
575	/// Since this function accesses TLS, `None` might be returned if the current thread's TLS is
576	/// tearing down.
577	#[inline]
578	fn current_index() -> Option<usize> {
579	    REGISTRATION.try_with(|reg| reg.index).ok()
580	}
581	
582	/// The global registry keeping track of registered threads and indices.
583	struct ThreadIndices {
584	    /// Mapping from `ThreadId` to thread index.
585	    mapping: HashMap<ThreadId, usize>,
586	
587	    /// A list of free indices.
588	    free_list: Vec<usize>,
589	
590	    /// The next index to allocate if the free list is empty.
591	    next_index: usize,
592	}
593	
594	fn thread_indices() -> &'static Mutex<ThreadIndices> {
595	    static THREAD_INDICES: OnceLock<Mutex<ThreadIndices>> = OnceLock::new();
596	    fn init() -> Mutex<ThreadIndices> {
597	        Mutex::new(ThreadIndices {
598	            mapping: HashMap::new(),
599	            free_list: Vec::new(),
600	            next_index: 0,
601	        })
602	    }
603	    THREAD_INDICES.get_or_init(init)
604	}
605	
606	/// A registration of a thread with an index.
607	///
608	/// When dropped, unregisters the thread and frees the reserved index.
609	struct Registration {
610	    index: usize,
611	    thread_id: ThreadId,
612	}
613	
614	impl Drop for Registration {
615	    fn drop(&mut self) {
616	        let mut indices = thread_indices().lock().unwrap();
617	        indices.mapping.remove(&self.thread_id);
618	        indices.free_list.push(self.index);
619	    }
620	}
621	
622	std::thread_local! {
623	    static REGISTRATION: Registration = {
624	        let thread_id = thread::current().id();
625	        let mut indices = thread_indices().lock().unwrap();
626	
627	        let index = match indices.free_list.pop() {
628	            Some(i) => i,
629	            None => {
630	                let i = indices.next_index;
631	                indices.next_index += 1;
632	                i
633	            }
634	        };
635	        indices.mapping.insert(thread_id, index);
636	
637	        Registration {
638	            index,
639	            thread_id,
640	        }
641	    };
642	}
